#include <bits/stdc++.h>
using namespace std;
int main(){
    string s;
    int t=0;
    cin>>s;
    stack<int> st;
    for(int i=0;i<s.size();i++){
        if(s[i]>='0' && s[i]<='9')
            t=t*10+s[i]-'0';
        else if(s[i]=='.')
            st.push(t),t=0;
        else if(s[i]=='+'){
            int a,b;
            a=st.top(),st.pop(),b=st.top(),st.pop();
            st.push(a+b);
        }else if(s[i]=='-'){
            int a,b;
            a=st.top(),st.pop(),b=st.top(),st.pop();
            st.push(b-a);
        }else if(s[i]=='*'){
            int a,b;
            a=st.top(),st.pop(),b=st.top(),st.pop();
            st.push(a*b);
        }else if(s[i]=='/'){
            int a,b;
            a=st.top(),st.pop(),b=st.top(),st.pop();
            st.push(b/a);
        }else
            break;
    }
    printf("%d",st.top());
    return 0;
}
